+pub fn addmm_tensor_contiguous_f64(
+    input: &[f64],
+    mat1: &[f64],
+    mat2: &[f64],
+    input_meta: &TensorMeta,
+    mat1_meta: &TensorMeta,
+    mat2_meta: &TensorMeta,
